#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    void backtrack(vector<vector<int>>& result, vector<int>& path, const vector<int>& nums, int k, int start) {
        if (path.size() == k) {
            result.push_back(path);
            return;
        }
        for (int i = start; i < nums.size(); i++) {
            if (i > start && nums[i] == nums[i-1]) {
                continue;
            }
            path.push_back(nums[i]);
            backtrack(result, path, nums, k, i + 1);
            path.pop_back();
        }
    }

public:
    vector<vector<int>> subsetsWithDup(vector<int>& nums, int k) {
        sort(nums.begin(), nums.end());
        vector<vector<int>> result;
        vector<int> path;
        backtrack(result, path, nums, k, 0);
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    if (!(cin >> t)) return 0;
    int n;
    if (!(cin >> n)) return 0;
    int k;
    if (!(cin >> k)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    Solution sol;
    vector<vector<int>> ans = sol.subsetsWithDup(nums, k);
    cout << ans.size() << "\n";
    for (const auto& subset : ans) {
        for (int i = 0; i < subset.size(); i++) {
            cout << subset[i] << (i == subset.size() - 1 ? "" : " ");
        }
        cout << "\n";
    }
    return 0;
}
